import{_ as t,o as i,c as e,ag as a}from"./chunks/framework.WmBmIPw-.js";const d=JSON.parse('{"title":"插入启发式（Insertion Heuristics）","description":"","frontmatter":{},"headers":[],"relativePath":"or-opt/insertion-heuristics.md","filePath":"or-opt/insertion-heuristics.md","lastUpdated":1777189692000}'),s={name:"or-opt/insertion-heuristics.md"};function n(o,r,l,h,c,g){return i(),e("div",null,[...r[0]||(r[0]=[a('<h1 id="插入启发式-insertion-heuristics" tabindex="-1">插入启发式（Insertion Heuristics） <a class="header-anchor" href="#插入启发式-insertion-heuristics" aria-label="Permalink to &quot;插入启发式（Insertion Heuristics）&quot;">​</a></h1><p>插入启发式在构造式框架下，从较小的初始对象（TSP 中常为一小段路径或星形、VRP 中多从车场出发的短路径）开始，在每一步把一个尚未接待的客户插入到当前路径或某条路径的某条弧上（弧被拆成两段、客户落在两段之间），使插入后仍可行，且增量长度、时间窗违罚等启发式代价可接受。是路径类问题（TSP、CVRP、带时间窗）里最常用的构造族之一。属 <a href="./simple-heuristics.html">基础启发式</a> 的构造式；与 <a href="./clarke-wright-savings.html">Clarke–Wright 节约</a>、<a href="./greedy-algorithm.html">贪心（构造式）</a> 并列。见 <a href="./heuristic-algorithms.html">启发式算法总览</a>。</p><hr><h2 id="通用一步长-最小化、可行" tabindex="-1">通用一步长（最小化、可行） <a class="header-anchor" href="#通用一步长-最小化、可行" aria-label="Permalink to &quot;通用一步长（最小化、可行）&quot;">​</a></h2><ul><li><strong>输入</strong>：已有一条或多条路径表示当前解的开或闭子结构。</li><li><strong>候选</strong>：对「下一个待插入客户 v」与「路径上某插入位置（落在弧 (i, j) 上）」的组合，可计算插入增量 Δ(v, i, j)。在最小化距离时常为：插入后 d(i, v) + d(v, j) 减去原弧 d(i, j)，再对容量、时间窗、车载等加罚；不可行则排除。</li><li><strong>规则</strong>：在全体可行对上取 Δ 最小（最廉插入），或采用 regret、或在前若干好位置中随机等。</li><li><strong>止</strong>：客户全部进路径或违反主约束不能继续。</li></ul><hr><h2 id="常见插入准则-tsp-vrp-文献" tabindex="-1">常见插入准则（TSP/VRP 文献） <a class="header-anchor" href="#常见插入准则-tsp-vrp-文献" aria-label="Permalink to &quot;常见插入准则（TSP/VRP 文献）&quot;">​</a></h2><ul><li><strong>最廉（cheapest）</strong>：当前步在全体可行插入对上取增量最小。</li><li><strong>最远（farthest 等）</strong>：用于先选下一个待插谁时，先选离当前构造几何上最远的未访点，再定位置；可与最近策略交替。</li><li><strong>Regret 插入</strong>：若某客户插在次优位与最优位的代价差大，优先安排该客户；精确定义见各文献与 <a href="./alns.html">ALNS</a> 中的 regret 修复。</li><li><strong>随机化最廉</strong>：在增量低于阈值的多个插入对中随机，与 RCL/GRASP 精神一致。</li></ul><p><strong>注</strong>：CVRP 中「插到哪条车、按何顺序选客户、超载时是否开新车」比 TSP 多一层，但插入增量与可行检查思路相同。</p><hr><h2 id="与-alns-节约法的关系" tabindex="-1">与 ALNS/节约法的关系 <a class="header-anchor" href="#与-alns-节约法的关系" aria-label="Permalink to &quot;与 ALNS/节约法的关系&quot;">​</a></h2><ul><li><a href="./alns.html">ALNS</a> 的修复子程序常把移出点重插，是在部分解上反复插拔，属于大邻域里的一步，不是一步从空构到尾的纯插入构造。</li><li><a href="./clarke-wright-savings.html">Clarke–Wright 节约</a> 是边合并式构造，不是逐步把单客户插到弧上；路径成形后可用插入法改进或作修复。</li></ul><p><strong>注</strong>：实现上须固定弧上有序插入的编码与不可行时的回退或惩罚，并在可复现说明中写清。</p>',13)])])}const p=t(s,[["render",n]]);export{d as __pageData,p as default};
